package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.Test;

class LineItemTest {

  @Test
  void testToString() throws Exception {
    Object item = createLineItem("apple", 3, 2500000L, "USD");
    String expected = "(item: apple, qty: 3, price: 2.50 USD)";
    assertEquals(expected, item.toString());
  }

  @Test
  void testToString_zeroQuantityAndPrice() throws Exception {
    Object item = createLineItem("banana", 0, 0L, "EUR");
    String expected = "(item: banana, qty: 0, price: 0.00 EUR)";
    assertEquals(expected, item.toString());
  }

  @Test
  void testToString_nullNameAndCurrency() throws Exception {
    Object item = createLineItem(null, 5, 123456789L, null);
    String expected = "(item: null, qty: 5, price: 123.46 null)";
    assertEquals(expected, item.toString());
  }

  private Object createLineItem(String name, int quantity, long priceInMicros, String currencyCode) throws Exception {
    // Use the class directly instead of Class.forName to avoid ClassNotFoundException
    Class<LineItem> clazz = LineItem.class;
    return clazz.getConstructor(String.class, int.class, long.class, String.class)
        .newInstance(name, quantity, priceInMicros, currencyCode);
  }
}
